module RefModule(
        c_in,
        d_in,
        out1
    );

    // SIGNAL DECLARATIONS
    input c_in;
    input d_in;
    output out1;
    wire out1;
    wire temp;

  wire temp1_c_in = c_in;
  wire temp2_d_in = d_in;
  assign temp = temp1_c_in & temp2_d_in;
    assign out1 = temp ^ d_in;

endmodule
